#include <stdio.h>
#include <stdlib.h>
#include <math.h>

#define N 100005

int main() {
    int N, m, c, x, y, p, i, j;
    scanf("%d", &N);
    int houses[N][3];
    for (i = 0; i < N; i++) {
        scanf("%d %d %d", &houses[i][0], &houses[i][1], &houses[i][2]);
    }
    scanf("%d %d", &m, &c);
    int maxPower = 0;
    for (i = 0; i < N; i++) {
        x = houses[i][0];
        y = houses[i][1];
        p = houses[i][2];
        if (y - m * x > c) {
            maxPower = max(maxPower, p);
        } else {
            maxPower = max(maxPower, -p);
        }
    }
    printf("%d\n", maxPower);
    return 0;
}

