            houses[i][1] = scanner.nextInt();
            houses[i][2] = scanner.nextInt();
        }
        int maxPower = 0;
        for (int i = 0; i < N; i++) {
            int x = houses[i][0];
            int y = houses[i][1];
            int p = houses[i][2];
            if (y - m * x > c) {
                maxPower = Math.max(maxPower, p);
            } else {
                maxPower = Math.max(maxPower, -p);
            }
        }
